    display: block;
    margin: 0 auto;
    background: linear-gradient(180deg, #0b1220, #0f172a);
    box-shadow: 0 0 0 2px rgba(255,255,255,0.08), 0 10px 30px rgba(0,0,0,0.4);
    border-radius: 12px;
