  ctx.font = "12px Arial";
  ctx.fillStyle = "#cbd5e1";
  ctx.fillText("紫色=加速成长  黄色=高分  可穿墙", 18, 73);
  ctx.restore();
}

function drawOverlay(title, text) {
  ctx.save();
  ctx.fillStyle = "rgba(2, 6, 23, 0.72)";
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  ctx.fillStyle = "rgba(15, 23, 42, 0.92)";
  roundRect(ctx, 26, 180, 308, 240, 18);
  ctx.fill();

  ctx.strokeStyle = "rgba(255,255,255,0.12)";
  ctx.lineWidth = 2;
  roundRect(ctx, 26, 180, 308, 240, 18);
  ctx.stroke();

  ctx.textAlign = "center";
  ctx.fillStyle = "#fff";
  ctx.font = "bold 26px Arial";
  ctx.fillText(title, canvas.width / 2, 225);

  ctx.font = "15px Arial";
  ctx.fillStyle = "#d1d5db";
  const lines = text.split("\n");
  lines.forEach((line, i) => {
    ctx.fillText(line, canvas.width / 2, 270 + i * 26);
  });

  ctx.font = "12px Arial";
  ctx.fillStyle = "#94a3b8";
  ctx.fillText("目标：活得更久，拿更高分", canvas.width / 2, 392);
  ctx.textAlign = "start";
  ctx.restore();
}

// ====== 主循环 ======
function loop(ts) {
  if (!lastTime) lastTime = ts;
  const dt = Math.min(32, ts - lastTime);
  lastTime = ts;

  update(dt);
  draw();

  requestAnimationFrame(loop);
}

// 启动
resetGame();
requestAnimationFrame(loop);
